const MONITORS = [
  { id: 'homepage-en', name: 'Homepage EN', url: 'https://www.kalanera.gr/', needles: ['business-list'] },
  { id: 'homepage-el', name: 'Homepage EL', url: 'https://www.kalanera.gr/index-el.html', needles: ['business-list'] },
  { id: 'business-json', name: 'Bedrijven JSON', url: 'https://www.kalanera.gr/data/local-businesses.json', jsonMinActive: 50 },
  { id: 'pwa-manifest', name: 'PWA manifest', url: 'https://www.kalanera.gr/manifest.json', needles: ['standalone'] },
  { id: 'n8n-business', name: 'n8n bedrijven webhook', url: 'https://n8n.vanlaar.cloud/webhook/local-businesses', jsonMinActive: 50 },
  { id: 'n8n-bus', name: 'n8n bus', url: 'https://n8n.vanlaar.cloud/webhook/bus-schedule-next?dir=volos&remaining=0&dayOffset=0', busMinItems: 0 },
];

const JSON_URL = 'https://www.kalanera.gr/data/local-businesses.json';
const WEBHOOK_URL = 'https://n8n.vanlaar.cloud/webhook/local-businesses';

function escHtml(s) {
  return String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function toBodyHtml(lines) {
  const htmlLines = lines.map((line) => {
    if (!line) return '<br>';
    if (line.startsWith('===')) {
      const title = line.replace(/^=+\s*|\s*=+$/g, '');
      return `<h3 style="margin:16px 0 6px;font-size:15px">${escHtml(title)}</h3>`;
    }
    let color = '#1a1a1a';
    if (/^OK\b/.test(line) || /^Status: OK/.test(line)) color = '#0d7a3e';
    if (/^FAIL\b/.test(line) || /PROBLEEM|aandachtspunten/i.test(line)) color = '#b42318';
    if (/^WARN\b/.test(line)) color = '#b54708';
    return `<p style="margin:3px 0;color:${color}">${escHtml(line)}</p>`;
  }).join('\n');
  return `<!DOCTYPE html><html><body style="font-family:system-ui,Segoe UI,Roboto,sans-serif;font-size:14px;line-height:1.45;color:#1a1a1a;max-width:42em;padding:8px 4px">${htmlLines}</body></html>`;
}

function sheetStatus(row) {
  return String(row?.Status ?? row?.status ?? row?.STATUS ?? '').trim().toLowerCase();
}
function normalizeRows(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && Array.isArray(payload.rows)) return payload.rows;
  if (payload && Array.isArray(payload.data)) return payload.data;
  return [];
}
function countActive(payload) {
  return normalizeRows(payload).filter((r) => sheetStatus(r) === 'active').length;
}

async function httpGetJson(url) {
  const started = Date.now();
  try {
    const data = await this.helpers.httpRequest({ method: 'GET', url, json: true, timeout: 30000 });
    return { ok: true, ms: Date.now() - started, data };
  } catch (e) {
    return { ok: false, ms: Date.now() - started, error: e?.message || String(e) };
  }
}

async function httpGetText(url) {
  const started = Date.now();
  try {
    const raw = await this.helpers.httpRequest({ method: 'GET', url, timeout: 30000 });
    const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
    return { ok: true, ms: Date.now() - started, text };
  } catch (e) {
    return { ok: false, ms: Date.now() - started, error: e?.message || String(e) };
  }
}

const lines = [
  'Kalanera — wekelijks monitoringoverzicht',
  `Gegenereerd (UTC): ${new Date().toISOString()}`,
  '',
  '=== URL-checks (zoals UptimeRobot / check-site-availability.mjs) ===',
];

let urlFails = 0;
for (const m of MONITORS) {
  if (m.jsonMinActive != null || m.busMinItems != null) {
    const res = await httpGetJson.call(this, m.url);
    if (!res.ok) {
      urlFails += 1;
      lines.push(`FAIL  ${m.name} — ${res.error}`);
      continue;
    }
    if (m.jsonMinActive != null) {
      const n = countActive(res.data);
      const ga = res.data?.generatedAt || null;
      const status = n >= m.jsonMinActive ? 'OK' : 'FAIL';
      if (status === 'FAIL') urlFails += 1;
      lines.push(`${status}  ${m.name} — ${n} Active${ga ? `, generatedAt ${ga}` : ''} (${res.ms}ms)`);
    } else {
      const items = Array.isArray(res.data?.items) ? res.data.items.length : 0;
      const tz = res.data?.meta?.tz || '?';
      const status = tz === 'Europe/Athens' ? 'OK' : 'FAIL';
      if (status === 'FAIL') urlFails += 1;
      lines.push(`${status}  ${m.name} — tz=${tz}, items=${items} (${res.ms}ms)`);
    }
  } else {
    const res = await httpGetText.call(this, m.url);
    if (!res.ok) {
      urlFails += 1;
      lines.push(`FAIL  ${m.name} — ${res.error}`);
      continue;
    }
    const missing = (m.needles || []).filter((n) => !res.text.includes(n));
    const status = missing.length ? 'FAIL' : 'OK';
    if (status === 'FAIL') urlFails += 1;
    lines.push(`${status}  ${m.name} — HTTP OK${missing.length ? `, mist: ${missing.join(', ')}` : ''} (${res.ms}ms)`);
  }
}

lines.push('');
lines.push('=== JSON vs webhook (Active-rijen) ===');
const jsonRes = await httpGetJson.call(this, JSON_URL);
const whRes = await httpGetJson.call(this, WEBHOOK_URL);
let jsonActive = 0;
let webhookActive = 0;
let syncOk = false;
if (!jsonRes.ok || !whRes.ok) {
  lines.push(`FAIL  vergelijking — JSON: ${jsonRes.ok ? 'OK' : jsonRes.error}, webhook: ${whRes.ok ? 'OK' : whRes.error}`);
} else {
  jsonActive = countActive(jsonRes.data);
  webhookActive = countActive(whRes.data);
  const diff = Math.abs(jsonActive - webhookActive);
  syncOk = diff <= 2 && jsonActive >= 50;
  lines.push(`${syncOk ? 'OK' : 'WARN'}  JSON ${jsonActive} Active, webhook ${webhookActive} Active, verschil ${diff}`);
}

const overallOk = urlFails === 0 && syncOk;
lines.push('');
lines.push('=== Samenvatting ===');
lines.push(overallOk ? 'Alles groen — geen actie nodig deze week.' : 'Er zijn aandachtspunten — zie FAIL/WARN hierboven.');
lines.push('');
lines.push('UptimeRobot: apart dashboard voor uptime% en incident-historie.');
lines.push('GA4 web_vitals: Explore/Events voor performance-trends.');
lines.push('Lokaal: node scripts/check-site-availability.mjs');

const subject = overallOk
  ? '[kalanera] Weekoverzicht — alles OK'
  : '[kalanera] Weekoverzicht — aandachtspunten';
const body = lines.join('\n');

return [{
  json: {
    overallOk,
    urlFails,
    jsonActive,
    webhookActive,
    subject,
    body,
    bodyHtml: toBodyHtml(lines),
  },
}];
